@RestController
class UserController {
    private final OAuth2AuthorizedClientService authorizedClientService;

    public UserController(OAuth2AuthorizedClientService authorizedClientService) {
        this.authorizedClientService = authorizedClientService;
    }

    @GetMapping("/welcome")
    public Map<String, Object> welcome(HttpServletRequest request) {
        OAuth2AuthenticationToken authentication = (OAuth2AuthenticationToken) request.getUserPrincipal();
        OAuth2AuthorizedClient client = authorizedClientService.loadAuthorizedClient(
                authentication.getAuthorizedClientRegistrationId(), authentication.getName());
        OidcIdToken idToken = (OidcIdToken) client.getIdToken();

        return Map.of(
            "name", idToken.getClaims().get("name"),
            "email", idToken.getClaims().get("email")
        );
    }
}

